#!/bin/bash\n# Script de déploiement - Crawling Website Application\n# Usage: bash deploy.sh\n\nset -e\n\nAPP_DIR=\"/home/netit972/crawling-app\"\necho \"=== Deploying Crawling App to $APP_DIR ===\"\n\n# Create directories\nmkdir -p \"$APP_DIR/logs\"\nmkdir -p \"$APP_DIR/static\"\n\n# Install Python dependencies\necho \"Installing Python dependencies...\"\ncd \"$APP_DIR\"\npip3 install --user -r requirements.txt\n\n# Install Playwright browsers\necho \"Installing Playwright Chromium...\"\npython3 -m playwright install chromium\npython3 -m playwright install-deps chromium 2>/dev/null || true\n\n# Create logs directory\nmkdir -p logs\n\n# Test database connection\necho \"Testing database connection...\"\npython3 -c \"\nimport sys\nsys.path.insert(0, '$APP_DIR')\nfrom utils.database import DatabaseManager\ntry:\n    result = DatabaseManager.execute_query('SELECT COUNT(*) as cnt FROM APP_domaine', fetch='one')\n    print(f'  Crawling DB OK - {result[\\\"cnt\\\"]} domains')\nexcept Exception as e:\n    print(f'  Crawling DB ERROR: {e}')\n    sys.exit(1)\n\ntry:\n    result = DatabaseManager.execute_query('SELECT COUNT(*) as cnt FROM entreprises', db_name='sirene', fetch='one')\n    print(f'  SIRENE DB OK - {result[\\\"cnt\\\"]} entreprises')\nexcept Exception as e:\n    print(f'  SIRENE DB ERROR: {e}')\n    sys.exit(1)\n\"\n\necho \"\"\necho \"=== Deployment complete! ===\"\necho \"\"\necho \"To start all services:\"\necho \"  cd $APP_DIR && pm2 start ecosystem.config.js\"\necho \"\"\necho \"To start individual services:\"\necho \"  pm2 start ecosystem.config.js --only http-checker\"\necho \"  pm2 start ecosystem.config.js --only crawler\"\necho \"  pm2 start ecosystem.config.js --only siretisation\"\necho \"  pm2 start ecosystem.config.js --only dashboard\"\necho \"\"\necho \"To monitor:\"\necho \"  pm2 status\"\necho \"  pm2 logs\"\necho \"\"\necho \"Dashboard: http://srv1.net-it-be.com:5050\"\n